import { h } from '@stencil/core';
import { dispatchModalEvent } from '../../utils/modalEvents';
import { InitialCardProps } from '../zeptypes';

export const InitialCard = ({ 
  handleProceedQuiz, 
  handleProceedQuizTwo, 
  quizTitle, 
  isLoading, 
  btnTitle,
  btnTitleTwo 
}: InitialCardProps) => {
  // Dispatch should-unbleed event on mount
  dispatchModalEvent('should-unbleed');
  const announcement = `${quizTitle}. Choose your quiz type: ${btnTitle}${handleProceedQuizTwo ? ` or ${btnTitleTwo}` : ''}`;

  return (
    <div class="parent-container initial-side-card d-flex">
      <div 
        role="status" 
        aria-live="polite" 
        aria-atomic="true"
        style={{
          position: 'absolute',
          width: '1px',
          height: '1px',
          padding: '0',
          margin: '-1px',
          overflow: 'hidden',
          clip: 'rect(0, 0, 0, 0)',
          whiteSpace: 'nowrap',
          border: '0'
        }}
      >
        {announcement}
      </div>
      <div class="flex-row justify-content-start gap-3" aria-labelledby="initial-label">
        <div class="parent-container-child initial-side-card">
          <div class="parent-container__content">
          <h2 class="parent-container_child__header">{quizTitle}</h2>
          </div>
          <div class="parent-container_child__button">
              <zepbutton-component label={btnTitle} isLoading={isLoading} onBtnClick={() => handleProceedQuiz()} btnId = "initial-quiz-start">
                {btnTitle}
              </zepbutton-component>
              {handleProceedQuizTwo && (
                <zepbutton-component
                  label={btnTitleTwo || 'Take Quiz 2'}
                  isLoading={isLoading} 
                  onBtnClick={() => handleProceedQuizTwo()} 
                  btnId="initial-quiz-two-start"
                  class="mt-3"
                >
                  {btnTitleTwo || 'Take Quiz 2'}
                </zepbutton-component>
              )}
            </div>
        </div>
        <div class="parent-container__right___column"></div>
      </div>
    </div>
  );
};