import { h } from '@stencil/core';
import { dispatchModalEvent } from '../../utils/modalEvents';
import { ResultCardProps } from '../zeptypes';

import { archetypes, zepQuizStaticConstants } from '../zepbound-constants';

import { archTypeProvider } from '../helpers';


export const ResultZepCard = ({ pyBtnTitle, winningArchetypes = [], archetypeData ,hasDownloadedImage, onImageDownloaded }: ResultCardProps) => {
  // Dispatch should-unbleed event on mount
  dispatchModalEvent('should-unbleed');
  // Feedback state for success/error
  let feedback = '';
  // Email validation state
  let emailError = '';
  let emailErrorRef: HTMLParagraphElement | null = null;
  // Refs for form and input
  let formRef: HTMLFormElement | null = null;
  let emailInputRef: HTMLInputElement | null = null;

  // Archetype mapping for API
  const archetypeMapping = {
    'Storyteller': 'storyteller',
    'Visibility maker': 'maker',
    'Challenger': 'challenger',
    'Quiet Force': 'quiet-force',
  };

  // Email validation helper
  const isValidEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  // Email submit handler (called directly from button click)
  const handleEmailSubmit = async () => {
    console.log('handleEmailSubmit called');
    const form = formRef;
    console.log('Form ref:', form);
    if (!form) {
      console.log('Form ref not found, returning');
      return;
    }
    const emailInput = emailInputRef;
    const errorElement = emailErrorRef;
    console.log('Email input ref:', emailInput);
    if (!emailInput) {
      console.log('Email input ref not found, returning');
      return;
    }
    const emailValue = emailInput.value.trim();
    console.log('Email value:', emailValue);
    
    // Validate email
    if (!isValidEmail(emailValue)) {
      emailError = 'Invalid email address';
      if (errorElement) {
        errorElement.textContent = emailError;
        errorElement.style.display = 'block';
      }
      console.log('Invalid email format');
      return;
    }
    
    // Clear error if validation passes
    emailError = '';
    if (errorElement) {
      errorElement.textContent = '';
      errorElement.style.display = 'none';
    }
    
    // Match JS implementation for payload
    const rawArchetype = sessionStorage.getItem('quizResult') ?? 'storyteller';
    // Map the archetype to API format
    const archetype = archetypeMapping[rawArchetype] || rawArchetype.toLowerCase();
    const payload = {
      firstName: 'firstName',
      lastName: 'lastName',
      email: emailValue,
      phone: null,
      mmn: 'PP-IX-US-4600',
      programProduct: 'ZepBound',
      careProgram: 'US Zepbound Care Program',
      brandSiteUrl: 'https://www.zepbound.lilly.com',
      extAttributes: [
        {
          extAttribute_archetype: archetype,
          extAttribute_toc_quiz: 'taken',
        },
      ],
    };
    console.log('Prepared payload:', payload);
    try {
      const EXTERNAL_EMAIL_API_URL = 'https://edg.dev.apps.lilly.com/v1/crm';
      const res = await fetch(EXTERNAL_EMAIL_API_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });
      if (res.ok) {
        feedback = 'Email sent successfully!';
        window.alert(feedback);
        console.log('Email sent successfully');
        form.reset();
      } else {
        feedback = 'Failed to send email. Please try again.';
        console.error('Email sending failed with status:', res.status);
        window.alert(feedback);
      }
    } catch (err) {
      feedback = 'Error sending email. Please try again.';
      console.error('Error sending email:', err);
      window.alert(feedback);
    }
  };
  let currentArchetype = null;
  if (winningArchetypes.length >= 1) {
    if (Array.isArray(archetypeData) && archetypeData.length > 0) {
      currentArchetype = archTypeProvider(winningArchetypes[0], archetypeData);
    } else {
      currentArchetype = archetypes[winningArchetypes[0]];
    }
  }
  // Compose announcement text for screen readers, with image description last
  const resultAnnouncement = winningArchetypes.length >= 1
    ? [
        `Quiz complete! Your result is: The ${winningArchetypes[0]}`,
        currentArchetype?.description,
        currentArchetype?.subType,
        currentArchetype?.subtypeDescription,
        currentArchetype?.carryForward,
        `A button is available to ${pyBtnTitle}`,
        currentArchetype?.image ? `This result includes an illustration representing the ${winningArchetypes[0]} archetype` : null
      ].filter(Boolean).join('. ')
    : 'Complete the quiz to discover your Threadsetter style!';

  return (
    <div class="parent-container initial-side-card d-flex final-card" aria-label="Quiz Results">
      <div
        role="status"
        aria-live="polite"
        aria-atomic="true"
        style={{
          position: 'absolute',
          width: '1px',
          height: '1px',
          padding: '0',
          margin: '-1px',
          overflow: 'hidden',
          clip: 'rect(0, 0, 0, 0)',
          whiteSpace: 'nowrap',
          border: '0',
        }}
      >
        {resultAnnouncement}
      </div>
      <div class="d-flex justify-content-start parent-main__resulttwo___container" aria-labelledby="initial-label" id="result-card-container">
        <div class="parent-container-child">
          <div class="parent-container__content">
            <h2 class="parent-container_child__header">The {winningArchetypes[0]}</h2>

            {winningArchetypes.length >= 1 ? (
              <div>
                <p class="parent-container_child__paragraph">{currentArchetype?.description}</p>
                <p class="parent-container_child__paragraph_bold">{currentArchetype?.subType}</p>
                <p class="parent-container_child__paragraph">{currentArchetype?.subtypeDescription}</p>
                <p class="parent-container_child__paragraph">{currentArchetype?.carryForward}</p>
              </div>
            ) : (
              <p class="parent-container_child__paragraph">Complete the quiz to discover your Threadsetter style!</p>
            )}
          </div>
          <div class="parent-container_child__button result-zep-button">
            {/* button1 */}
            <zepbutton-component
              label={pyBtnTitle}
              btndisabled={hasDownloadedImage ? 'Yes' : 'No'}
              isArrow={!hasDownloadedImage}
              optionalStyles={hasDownloadedImage ? { color: '#6A6A6A', backgroundColor: '#E2E2E2' } : {}}
              onBtnClick={async () => {
                if (currentArchetype?.image) {
                  try {
                    const response = await fetch(currentArchetype.image);
                    const blob = await response.blob();
                    const url = URL.createObjectURL(blob);
                    const link = document.createElement('a');
                    link.href = url;
                    link.download = winningArchetypes[0] || 'archetype-image.jpg';
                    document.body.appendChild(link);
                    link.click();
                    document.body.removeChild(link);
                    URL.revokeObjectURL(url);
                    if (onImageDownloaded) onImageDownloaded(true);
                  } catch (e) {
                    console.error('Failed to download image', e);
                    if (onImageDownloaded) onImageDownloaded(false);
                  }
                } else {
                  if (onImageDownloaded) onImageDownloaded(false);
                }
              }}
              btnId="find-care-for-sleep-apnea"
            >
              {hasDownloadedImage ? zepQuizStaticConstants.imgDownloadToast : pyBtnTitle}
            </zepbutton-component>
          </div>
        </div>
        <div class="parent-container__right___column">
          {currentArchetype?.image && (
            <div class="archetype-image-container">
              <img src={currentArchetype.image} alt={`${currentArchetype.name} archetype illustration`} class="archetype-image" loading="lazy" />
            </div>
          )}
        </div>
      </div>
      
      {/* Email yourself UI - outside column structure but inside parent-main__result___container */}
      <div class="email-yourself-container">
        <h3 class="parent-container_child__email">Email to yourself.</h3>
        <p class="parent-container_child__paragraph">Want to have your archetype and social post sent directly to your inbox? Provide your email and you're on your way!</p>
          <form
            class="email-yourself-form"
            autocomplete="off"
            id="email-yourself-form"
            ref={el => { formRef = el; }}
          >
            <label htmlFor="email" class="input-box-label">Email (required)</label>
            <input
              type="email"
              name="email"
              id="email"
              placeholder="Email"
              class="email-yourself-input"
              required
              ref={el => { emailInputRef = el; }}
            />
            <p 
              class="email-error-message" 
              style={{ color: 'red', fontSize: '14px', marginTop: '4px', display: 'none' }}
              ref={el => { emailErrorRef = el; }}
              role="alert"
            ></p>
            <zepbutton-component
              label="Submit"
              btnId="email-yourself-submit"
              onBtnClick={e => {
                console.log('Zepbutton clicked');
                e.preventDefault();
                handleEmailSubmit();
              }}
              style={{ marginTop: '0.5rem' }}
            >
              Submit
            </zepbutton-component>
          </form>
      </div>
    </div>
  );
};
