import { h } from '@stencil/core';
import { dispatchModalEvent } from '../../utils/modalEvents';
import { QnACardProps } from '../zeptypes';
import { BackIcon } from '../svg/Svg';

const renderHighlightedWord = (question: string, word: string) => {
  const parts = question.split(new RegExp(`\\b${word}\\b`, 'g'));
  const matches = question.match(new RegExp(`\\b${word}\\b`, 'g')) || [];
  return (
    <span>
      {parts.map((part, idx) => (
        <span key={idx}>
          {part}
          {idx < matches.length && <strong>{word}</strong>}
        </span>
      ))}
    </span>
  );
};

export const QnACard = ({
  structure,
  clickHandle,
  isClicked,
  capturedAnswer: _capturedAnswer,
  capturedIndex,
  handleProceedToNextQuestion,
  status,
  handleProceedQuiz,
  isMobile,
}: QnACardProps) => {
  // Always dispatch should-bleed event when QnACard is rendered
  dispatchModalEvent('should-bleed');
  const optionRefs = [];
  const optionEntries = Object.entries(structure).filter(
    ([key]) => key.startsWith('option') && !key.includes('archetype')
  );

  const focusOption = (idx: number) => {
    optionRefs[idx] && optionRefs[idx].focus && optionRefs[idx].focus();
  };

    // Dispatch should-bleed event on mount (only once)
    if (typeof window !== 'undefined') {
      // Use a flag to ensure it only fires once per mount
      if (!(window as any).__qna_bleed_fired) {
        (window as any).__qna_bleed_fired = true;
        setTimeout(() => {
          const event = new CustomEvent('should-bleed', { bubbles: true });
          // Find the closest modal-overlay ancestor and dispatch
          const host = document.querySelector('modal-overlay');
          if (host) host.dispatchEvent(event);
        }, 0);
      }
    }
  const handleKeyDown = (e: KeyboardEvent, idx: number) => {
    const total = optionEntries.length;
    if (e.key === 'ArrowDown' || e.key === 'ArrowRight') {
      e.preventDefault();
      focusOption((idx + 1) % total);
      return;
    }
    if (e.key === 'ArrowUp' || e.key === 'ArrowLeft') {
      e.preventDefault();
      focusOption((idx - 1 + total) % total);
      return;
    }
    if (e.key === ' ' || e.key === 'Enter') {
      e.preventDefault();
      const [, value] = optionEntries[idx];
      clickHandle({ text: value, isCorrect: true, selectedIndex: idx }, idx);
    }
  };

  return (
    <div class="quiz-container">
      <div class="stats-wrapper">{status}</div>
      <div class="quiz-container__content">
        <div class="content-wrapper">
          <div class="left-column">
            <legend id="question-label" class={`mb-0 ${!isMobile && "pb-1"} ${structure?.sub_header ? 'mt-0' : ""}`}>
              <strong class="question_label__sub_header">{structure.sub_header}</strong>
              <br />
              {structure?.requiresHighlight
                ? renderHighlightedWord(structure?.question, structure?.highlight || '')
                : structure?.question}
            </legend>
            <div class="feedback-desktop"></div>
          </div>
          <div class="right-column">
            <form class="question-form" aria-labelledby="question-label">
              <fieldset>
                <div class="options-wrapper">
                  {optionEntries.map(([, value], idx) => {
                    const isSelected = isClicked && capturedIndex === idx;
                    return (
                      <button
                        key={idx}
                        ref={(el) => (optionRefs[idx] = el)}
                        type="button"
                        class={`option-button ${isSelected ? 'selected' : ''}`}
                        onClick={() => clickHandle({ text: value, isCorrect: true, selectedIndex: idx }, idx)}
                        onKeyDown={(e) => handleKeyDown(e, idx)}
                        disabled={false}
                        aria-label={`option ${idx + 1} of ${optionEntries.length} ${value} ${isSelected ? 'selected' : 'not selected'}`}
                      >
                        <span class="option-text" aria-hidden="true">{value}</span>
                      </button>
                    );
                  })}
                </div>
              </fieldset>
            </form>
          </div>
        </div>
        <div class="navigation-wrapper">
          <div class="button-container">
            <div class="osa-toast__back">
              <button
                id="back-btn"
                type="button"
                class={`back-button${isMobile && isClicked ? ' mobile-hide-when-continue' : ''}`}
                onClick={() => handleProceedQuiz()}
                onFocus={(e) => {
                  (e.target as HTMLButtonElement).setAttribute('aria-hidden', 'false');
                }}
                onBlur={(e) => {
                  (e.target as HTMLButtonElement).setAttribute('aria-hidden', 'true');
                }}
                aria-hidden="true"
                aria-label="Back"
              >
                <span class="bck-arrow" aria-hidden="true">
                  <BackIcon className="bck-arrow__icon" />
                </span>
                <span aria-hidden="true">Back</span>
              </button>
            </div>
            {isClicked && (
              <zepbutton-component label="Continue" onBtnClick={() => handleProceedToNextQuestion()}>
                Continue
              </zepbutton-component>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};
